item.description:
hbase kerberos 参数配置
conf = HBaseConfiguration.create(); conf.set(&ldquo;hadoop.security.authentication&rdquo;,&ldquo;Kerberos&rdquo;); conf.set(&ldquo;hbase.security.authentication&rdquo;,&ldquo;Kerberos&rdquo;); conf.set(&ldquo;hbase.zookeeper.quorum&rdquo;, ZOOKEEPER_LIST); conf.set(&ldquo;hbase.master.kerberos.principal&rdquo;,&ldquo;hbase/_HOST@GZHLWLGCSKDC&rdquo;); conf.set(&ldquo;hbase.regionserver.kerberos.principal&rdquo;, &ldquo;hbase/_HOST@GZHLWLGCSKDC&rdquo;); conf.set(HConstants.CLIENT_ZOOKEEPER_QUORUM,ZOOKEEPER_LIST); conf.set(HConstants.ZOOKEEPER_CLIENT_PORT,&ldquo;2181&rdquo;); conf.set(HConstants.ZOOKEEPER_ZNODE_PARENT,&quot;/hbase-secure&quot;);
UserGroupInformation.setConfiguration(conf); try { UserGroupInformation.loginUserFromKeytab(&quot;bdoc/admin@GZHLWLGCSKDC&quot;, &quot;/etc/security/keytabs/bdoc.keytab&quot;); conn = ConnectionFactory.createConnection(conf); admin = (HBaseAdmin) conn.getAdmin(); } catch (IOException e) { e.printStackTrace(); }
